const raw = $input.first().json;
const body = raw.body || raw;
// Normalizar para formato esperado por /api/offmarket-leads/manual
const lead = {
  nome: body.nome || body.title || body.address || 'Lead Apify ' + new Date().toISOString().substring(0,10),
  cidade: body.cidade || body.city || body.location || 'Lisboa',
  tipo_ativo: body.tipo_ativo || body.propertyType || 'apartamento',
  // Campos opcionais enriquecidos
  localizacao: body.localizacao || body.morada || body.address || null,
  price_ask: body.price_ask || body.price ? Number(body.price_ask || body.price) : null,
  area_m2: body.area_m2 || body.area ? Number(body.area_m2 || body.area) : null,
  contacto: body.contacto || body.contact || null,
  owner_name: body.owner_name || body.owner || null,
  contact_phone_owner: body.contact_phone_owner || body.phone || null,
  source: body.source || 'apify',
  urgency: body.urgency || 'unknown',
  notes: body.notes || body.notas || body.description
    ? (body.notes || body.notas || body.description || '').substring(0, 500)
    : null
};
// Limpar nulos
Object.keys(lead).forEach(k => { if (lead[k] === null) delete lead[k]; });
return [{ json: lead }];

const resp = $input.first().json;
// Portal API retorna: { success, lead_id, score, nome, cidade, ... }
if (!resp.success) {
  console.log('[WF-G] Portal API error:', JSON.stringify(resp).substring(0, 300));
  return [{ json: { id: null, _error: true, _raw: JSON.stringify(resp).substring(0, 200) } }];
}
// score já calculado pelo pipeline completo
const score = resp.score ?? 0;
const tier = score >= 70 ? 'A' : score >= 40 ? 'B' : 'C';
console.log('[WF-G] Lead criado:', resp.lead_id, 'score:', score, 'tier:', tier);
return [{ json: { ...resp, id: resp.lead_id, computed_score: score, tier } }];
